    "content": "{"content":"// SPDX-License-Identifier: GPL-2.0\n/*\n *  linux/fs/stat.c\n *\n *  Copyright (C) 1991, 1992  Linus Torvalds\n */\n\n#include <linux/blkdev.h>\n#include <linux/export.h>\n#include <linux/mm.h>\n#include <linux/errno.h>\n#include <linux/file.h>\n#include <linux/highuid.h>\n#include <linux/fs.h>\n#include <linux/namei.h>\n#include <linux/security.h>\n#include <linux/cred.h>\n#include <linux/syscalls.h>\n#include <linux/pagemap.h>\n#include <linux/compat.h>\n#include <linux/iversion.h>\n\n#include <linux/uaccess.h>\n#include <asm/unistd.h>\n\n#include <trace/events/timestamp.h>\n\n#include \"internal.h\"\n#include \"mount.h\"\n\n/**\n * fill_mg_cmtime - Fill in the mtime and ctime and flag ctime as QUERIED\n * @stat: where to store the resulting values\n * @request_mask: STATX_* values requested\n * @inode: inode from which to grab the c/mtime\n *\n * Given @inode, grab the ctime and mtime out if it and store the result\n * in @stat. When fetching the value, flag it as QUERIED (if not already)\n * so the next write will record a distinct timestamp.\n *\n * NB: The QUERIED flag is tracked in the ctime, but we set it there even\n * if only the mtime was requested, as that ensures that the next mtime\n * change will be distinct.\n */\nvoid fill_mg_cmtime(struct kstat *stat, u32 request_mask, struct inode *inode)\n{\n\tatomic_t *pcn = (atomic_t *)&inode->i_ctime_nsec;\n\n\t/* If neither time was requested, then don't report them */\n\tif (!(request_mask & (STATX_CTIME|STATX_MTIME))) {\n\t\tstat->result_mask &= ~(STATX_CTIME|STATX_MTIME);\n\t\treturn;\n\t}\n\n\tstat->mtime = inode_get_mtime(inode);\n\tstat->ctime.tv_sec = inode->i_ctime_sec;\n\tstat->ctime.tv_nsec = (u32)atomic_read(pcn);\n\tif (!(stat->ctime.tv_nsec & I_CTIME_QUERIED))\n\t\tstat->ctime.tv_nsec = ((u32)atomic_fetch_or(I_CTIME_QUERIED, pcn));\n\tstat->ctime.tv_nsec &= ~I_CTIME_QUERIED;\n\ttrace_fill_mg_cmtime(inode, &stat->ctime, &stat->mtime);\n}\nEXPORT_SYMBOL(fill_mg_cmtime);\n\n/**\n * generic_fillattr - Fill in the basic attributes from the inode struct\n * @idmap:\t\tidmap of the mount the inode was found from\n * @request_mask:\tstatx request_mask\n * @inode:\t\tInode to use as the source\n * @stat:\t\tWhere to fill in the attributes\n *\n * Fill in the basic attributes in the kstat structure from data that's to be\n * found on the VFS inode structure.  This is the default if no getattr inode\n * operation is supplied.\n *\n * If the inode has been found through an idmapped mount the idmap of\n * the vfsmount must be passed through @idmap. This function will then\n * take care to map the inode according to @idmap before filling in the\n * uid and gid filds. On non-idmapped mounts or if permission checking is to be\n * performed on the raw inode simply pass @nop_mnt_idmap.\n */\nvoid generic_fillattr(struct mnt_idmap *idmap, u32 request_mask,\n\t\t      struct inode *inode, struct kstat *stat)\n{\n\tvfsuid_t vfsuid = i_uid_into_vfsuid(idmap, inode);\n\tvfsgid_t vfsgid = i_gid_into_vfsgid(idmap, inode);\n\n\tstat->dev = inode->i_sb->s_dev;\n\tstat->ino = inode->i_ino;\n\tstat->mode = inode->i_mode;\n\tstat->nlink = inode->i_nlink;\n\tstat->uid = vfsuid_into_kuid(vfsuid);\n\tstat->gid = vfsgid_into_kgid(vfsgid);\n\tstat->rdev = inode->i_rdev;\n\tstat->size = i_size_read(inode);\n\tstat->atime = inode_get_atime(inode);\n\n\tif (is_mgtime(inode)) {\n\t\tfill_mg_cmtime(stat, request_mask, inode);\n\t} else {\n\t\tstat->ctime = inode_get_ctime(inode);\n\t\tstat->mtime = inode_get_mtime(inode);\n\t}\n\n\tstat->blksize = i_blocksize(inode);\n\tstat->blocks = inode->i_blocks;\n\n\tif ((request_mask & STATX_CHANGE_COOKIE) && IS_I_VERSION(inode)) {\n\t\tstat->result_mask |= STATX_CHANGE_COOKIE;\n\t\tstat->change_cookie = inode_query_iversion(inode);\n\t}\n\n}\nEXPORT_SYMBOL(generic_fillattr);\n\n/**\n * generic_fill_statx_attr - Fill in the statx attributes from the inode flags\n * @inode:\tInode to use as the source\n * @stat:\tWhere to fill in the attribute flags\n *\n * Fill in the STATX_ATTR_* flags in the kstat structure for properties of the\n * inode that are published on i_flags and enforced by the VFS.\n */\nvoid generic_fill_statx_attr(struct inode *inode, struct kstat *stat)\n{\n\tif (inode->i_flags & S_IMMUTABLE)\n\t\tstat->attributes |= STATX_ATTR_IMMUTABLE;\n\tif (inode->i_flags & S_APPEND)\n\t\tstat->attributes |= STATX_ATTR_APPEND;\n\tstat->attributes_mask |= KSTAT_ATTR_VFS_FLAGS;\n}\nEXPORT_SYMBOL(generic_fill_statx_attr);\n\n/**\n * generic_fill_statx_atomic_writes - Fill in atomic writes statx attributes\n * @stat:\tWhere to fill in the attribute flags\n * @unit_min:\tMinimum supported atomic write length in bytes\n * @unit_max:\tMaximum supported atomic write length in bytes\n * @unit_max_opt: Optimised maximum supported atomic write length in bytes\n *\n * Fill in the STATX{_ATTR}_WRITE_ATOMIC flags in the kstat structure from\n * atomic write unit_min and unit_max values.\n */\nvoid generic_fill_statx_atomic_writes(struct kstat *stat,\n\t\t\t\t      unsigned int unit_min,\n\t\t\t\t      unsigned int unit_max,\n\t\t\t\t      unsigned int unit_max_opt)\n{\n\t/* Confirm that the request type is known */\n\tstat->result_mask |= STATX_WRITE_ATOMIC;\n\n\t/* Confirm that the file attribute type is known */\n\tstat->attributes_mask |= STATX_ATTR_WRITE_ATOMIC;\n\n\tif (unit_min) {\n\t\tstat->atomic_write_unit_min = unit_min;\n\t\tstat->atomic_write_unit_max = unit_max;\n\t\tstat->atomic_write_unit_max_opt = unit_max_opt;\n\t\t/* Initially only allow 1x segment */\n\t\tstat->atomic_write_segments_max = 1;\n\n\t\t/* Confirm atomic writes are actually supported */\n\t\tstat->attributes |= STATX_ATTR_WRITE_ATOMIC;\n\t}\n}\nEXPORT_SYMBOL_GPL(generic_fill_statx_atomic_writes);\n\n/**\n * vfs_getattr_nosec - getattr without security checks\n * @path: file to get attributes from\n * @stat: structure to return attributes in\n * @request_mask: STATX_xxx flags indicating what the caller wants\n * @query_flags: Query mode (AT_STATX_SYNC_TYPE)\n *\n * Get attributes without calling security_inode_getattr.\n *\n * Currently the only caller other than vfs_getattr is internal to the\n * filehandle lookup code, which uses only the inode number and returns no\n * attributes to any user.  Any other code probably wants vfs_getattr.\n */\nint vfs_getattr_nosec(const struct path *path, struct kstat *stat,\n\t\t      u32 request_mask, unsigned int query_flags)\n{\n\tstruct mnt_idmap *idmap;\n\tstruct inode *inode = d_backing_inode(path->dentry);\n\n\tmemset(stat, 0, sizeof(*stat));\n\tstat->result_mask |= STATX_BASIC_STATS;\n\tquery_flags &= AT_STATX_SYNC_TYPE;\n\n\t/* allow the fs to override these if it really wants to */\n\t/* SB_NOATIME means filesystem supplies dummy atime value */\n\tif (inode->i_sb->s_flags & SB_NOATIME)\n\t\tstat->result_mask &= ~STATX_ATIME;\n\n\t/*\n\t * Note: If you add another clause to set an attribute flag, please\n\t * update attributes_mask below.\n\t */\n\tif (IS_AUTOMOUNT(inode))\n\t\tstat->attributes |= STATX_ATTR_AUTOMOUNT;\n\n\tif (IS_DAX(inode))\n\t\tstat->attributes |= STATX_ATTR_DAX;\n\n\tstat->attributes_mask |= (STATX_ATTR_AUTOMOUNT |\n\t\t\t\t  STATX_ATTR_DAX);\n\n\tidmap = mnt_idmap(path->mnt);\n\tif (inode->i_op->getattr) {\n\t\tint ret;\n\n\t\tret = inode->i_op->getattr(idmap, path, stat, request_mask,\n\t\t\t\tquery_flags);\n\t\tif (ret)\n\t\t\treturn ret;\n\t} else {\n\t\tgeneric_fillattr(idmap, request_mask, inode, stat);\n\t}\n\n\t/*\n\t * If this is a block device inode, override the filesystem attributes\n\t * with the block device specific parameters that need to be obtained\n\t * from the bdev backing inode.\n\t */\n\tif (S_ISBLK(stat->mode))\n\t\tbdev_statx(path, stat, request_mask);\n\n\treturn 0;\n}\nEXPORT_SYMBOL(vfs_getattr_nosec);\n\n/*\n * vfs_getattr - Get the enhanced basic attributes of a file\n * @path: The file of interest\n * @stat: Where to return the statistics\n * @request_mask: STATX_xxx flags indicating what the caller wants\n * @query_flags: Query mode (AT_STATX_SYNC_TYPE)\n *\n * Ask the filesystem for a file's attributes.  The caller must indicate in\n * request_mask and query_flags to indicate what they want.\n *\n * If the file is remote, the filesystem can be forced to update the attributes\n * from the backing store by passing AT_STATX_FORCE_SYNC in query_flags or can\n * suppress the update by passing AT_STATX_DONT_SYNC.\n *\n * Bits must have been set in request_mask to indicate which attributes the\n * caller wants retrieving.  Any such attribute not requested may be returned\n * anyway, but the value may be approximate, and, if remote, may not have been\n * synchronised with the server.\n *\n * 0 will be returned on success, and a -ve error code if unsuccessful.\n */\nint vfs_getattr(const struct path *path, struct kstat *stat,\n\t\tu32 request_mask, unsigned int query_flags)\n{\n\tint retval;\n\n\tretval = security_inode_getattr(path);\n\tif (unlikely(retval))\n\t\treturn retval;\n\treturn vfs_getattr_nosec(path, stat, request_mask, query_flags);\n}\nEXPORT_SYMBOL(vfs_getattr);\n\n/**\n * vfs_fstat - Get the basic attributes by file descriptor\n * @fd: The file descriptor referring to the file of interest\n * @stat: The result structure to fill in.\n *\n * This function is a wrapper around vfs_getattr().  The main difference is\n * that it uses a file descriptor to determine the file location.\n *\n * 0 will be returned on success, and a -ve error code if unsuccessful.\n */\nint vfs_fstat(int fd, struct kstat *stat)\n{\n\tCLASS(fd_raw, f)(fd);\n\tif (fd_empty(f))\n\t\treturn -EBADF;\n\treturn vfs_getattr(&fd_file(f)->f_path, stat, STATX_BASIC_STATS, 0);\n}\n\nstatic int statx_lookup_flags(int flags)\n{\n\tint lookup_flags = 0;\n\n\tif (!(flags & AT_SYMLINK_NOFOLLOW))\n\t\tlookup_flags |= LOOKUP_FOLLOW;\n\tif (!(flags & AT_NO_AUTOMOUNT))\n\t\tlookup_flags |= LOOKUP_AUTOMOUNT;\n\n\treturn lookup_flags;\n}\n\nstatic int vfs_statx_path(const struct path *path, int flags, struct kstat *stat,\n\t\t\t  u32 request_mask)\n{\n\tint error = vfs_getattr(path, stat, request_mask, flags);\n\tif (error)\n\t\treturn error;\n\n\tif (request_mask & STATX_MNT_ID_UNIQUE) {\n\t\tstat->mnt_id = real_mount(path->mnt)->mnt_id_unique;\n\t\tstat->result_mask |= STATX_MNT_ID_UNIQUE;\n\t} else {\n\t\tstat->mnt_id = real_mount(path->mnt)->mnt_id;\n\t\tstat->result_mask |= STATX_MNT_ID;\n\t}\n\n\tif (path_mounted(path))\n\t\tstat->attributes |= STATX_ATTR_MOUNT_ROOT;\n\tstat->attributes_mask |= STATX_ATTR_MOUNT_ROOT;\n\treturn 0;\n}\n\nstatic int vfs_statx_fd(int fd, int flags, struct kstat *stat,\n\t\t\t  u32 request_mask)\n{\n\tCLASS(fd_raw, f)(fd);\n\tif (fd_empty(f))\n\t\treturn -EBADF;\n\treturn vfs_statx_path(&fd_file(f)->f_path, flags, stat, request_mask);\n}\n\n/**\n * vfs_statx - Get basic and extra attributes by filename\n * @dfd: A file descriptor representing the base dir for a relative filename\n * @filename: The name of the file of interest\n * @flags: Flags to control the query\n * @stat: The result structure to fill in.\n * @request_mask: STATX_xxx flags indicating what the caller wants\n *\n * This function is a wrapper around vfs_getattr().  The main difference is\n * that it uses a filename and base directory to determine the file location.\n * Additionally, the use of AT_SYMLINK_NOFOLLOW in flags will prevent a symlink\n * at the given name from being referenced.\n *\n * 0 will be returned on success, and a -ve error code if unsuccessful.\n */\nstatic int vfs_statx(int dfd, struct filename *filename, int flags,\n\t      struct kstat *stat, u32 request_mask)\n{\n\tstruct path path;\n\tunsigned int lookup_flags = statx_lookup_flags(flags);\n\tint error;\n\n\tif (flags & ~(AT_SYMLINK_NOFOLLOW | AT_NO_AUTOMOUNT | AT_EMPTY_PATH |\n\t\t      AT_STATX_SYNC_TYPE))\n\t\treturn -EINVAL;\n\nretry:\n\terror = filename_lookup(dfd, filename, lookup_flags, &path, NULL);\n\tif (error)\n\t\treturn error;\n\terror = vfs_statx_path(&path, flags, stat, request_mask);\n\tpath_put(&path);\n\tif (retry_estale(error, lookup_flags)) {\n\t\tlookup_flags |= LOOKUP_REVAL;\n\t\tgoto retry;\n\t}\n\treturn error;\n}\n\nint vfs_fstatat(int dfd, const char __user *filename,\n\t\t\t      struct kstat *stat, int flags)\n{\n\tCLASS(filename_maybe_null, name)(filename, flags);\n\n\tif (!name && dfd >= 0)\n\t\treturn vfs_fstat(dfd, stat);\n\n\treturn vfs_statx(dfd, name, flags | AT_NO_AUTOMOUNT,\n\t\t\t stat, STATX_BASIC_STATS);\n}\n\n#ifdef __ARCH_WANT_OLD_STAT\n\n/*\n * For backward compatibility?  Maybe this should be moved\n * into arch/i386 instead?\n */\nstatic int cp_old_stat(struct kstat *stat, struct __old_kernel_stat __user * statbuf)\n{\n\tstatic int warncount = 5;\n\tstruct __old_kernel_stat tmp;\n\n\tif (warncount > 0) {\n\t\twarncount--;\n\t\tprintk(KERN_WARNING \"VFS: Warning: %s using old stat() call. Recompile your binary.\\n\",\n\t\t\tcurrent->comm);\n\t} else if (warncount < 0) {\n\t\t/* it's laughable, but... */\n\t\twarncount = 0;\n\t}\n\n\tmemset(&tmp, 0, sizeof(struct __old_kernel_stat));\n\ttmp.st_dev = old_encode_dev(stat->dev);\n\ttmp.st_ino = stat->ino;\n\tif (sizeof(tmp.st_ino) < sizeof(stat->ino) && tmp.st_ino != stat->ino)\n\t\treturn -EOVERFLOW;\n\ttmp.st_mode = stat->mode;\n\ttmp.st_nlink = stat->nlink;\n\tif (tmp.st_nlink != stat->nlink)\n\t\treturn -EOVERFLOW;\n\tSET_UID(tmp.st_uid, from_kuid_munged(current_user_ns(), stat->uid));\n\tSET_GID(tmp.st_gid, from_kgid_munged(current_user_ns(), stat->gid));\n\ttmp.st_rdev = old_encode_dev(stat->rdev);\n#if BITS_PER_LONG == 32\n\tif (stat->size > MAX_NON_LFS)\n\t\treturn -EOVERFLOW;\n#endif\n\ttmp.st_size = stat->size;\n\ttmp.st_atime = stat->atime.tv_sec;\n\ttmp.st_mtime = stat->mtime.tv_sec;\n\ttmp.st_ctime = stat->ctime.tv_sec;\n\treturn copy_to_user(statbuf,&tmp,sizeof(tmp)) ? -EFAULT : 0;\n}\n\nSYSCALL_DEFINE2(stat, const char __user *, filename,\n\t\tstruct __old_kernel_stat __user *, statbuf)\n{\n\tstruct kstat stat;\n\tint error;\n\n\terror = vfs_stat(filename, &stat);\n\tif (unlikely(error))\n\t\treturn error;\n\n\treturn cp_old_stat(&stat, statbuf);\n}\n\nSYSCALL_DEFINE2(lstat, const char __user *, filename,\n\t\tstruct __old_kernel_stat __user *, statbuf)\n{\n\tstruct kstat stat;\n\tint error;\n\n\terror = vfs_lstat(filename, &stat);\n\tif (unlikely(error))\n\t\treturn error;\n\n\treturn cp_old_stat(&stat, statbuf);\n}\n\nSYSCALL_DEFINE2(fstat, unsigned int, fd, struct __old_kernel_stat __user *, statbuf)\n{\n\tstruct kstat stat;\n\tint error;\n\n\terror = vfs_fstat(fd, &stat);\n\tif (unlikely(error))\n\t\treturn error;\n\n\treturn cp_old_stat(&stat, statbuf);\n}\n\n#endif /* __ARCH_WANT_OLD_STAT */\n\n#ifdef __ARCH_WANT_NEW_STAT\n\n#ifndef INIT_STRUCT_STAT_PADDING\n#  define INIT_STRUCT_STAT_PADDING(st) memset(&st, 0, sizeof(st))\n#endif\n\nstatic int cp_new_stat(struct kstat *stat, struct stat __user *statbuf)\n{\n\tstruct stat tmp;\n\n\tif (sizeof(tmp.st_dev) < 4 && !old_valid_dev(stat->dev))\n\t\treturn -EOVERFLOW;\n\tif (sizeof(tmp.st_rdev) < 4 && !old_valid_dev(stat->rdev))\n\t\treturn -EOVERFLOW;\n#if BITS_PER_LONG == 32\n\tif (stat->size > MAX_NON_LFS)\n\t\treturn -EOVERFLOW;\n#endif\n\n\tINIT_STRUCT_STAT_PADDING(tmp);\n\ttmp.st_dev = new_encode_dev(stat->dev);\n\ttmp.st_ino = stat->ino;\n\tif (sizeof(tmp.st_ino) < sizeof(stat->ino) && tmp.st_ino != stat->ino)\n\t\treturn -EOVERFLOW;\n\ttmp.st_mode = stat->mode;\n\ttmp.st_nlink = stat->nlink;\n\tif (tmp.st_nlink != stat->nlink)\n\t\treturn -EOVERFLOW;\n\tSET_UID(tmp.st_uid, from_kuid_munged(current_user_ns(), stat->uid));\n\tSET_GID(tmp.st_gid, from_kgid_munged(current_user_ns(), stat->gid));\n\ttmp.st_rdev = new_encode_dev(stat->rdev);\n\ttmp.st_size = stat->size;\n\ttmp.st_atime = stat->atime.tv_sec;\n\ttmp.st_mtime = stat->mtime.tv_sec;\n\ttmp.st_ctime = stat->ctime.tv_sec;\n#ifdef STAT_HAVE_NSEC\n\ttmp.st_atime_nsec = stat->atime.tv_nsec;\n\ttmp.st_mtime_nsec = stat->mtime.tv_nsec;\n\ttmp.st_ctime_nsec = stat->ctime.tv_nsec;\n#endif\n\ttmp.st_blocks = stat->blocks;\n\ttmp.st_blksize = stat->blksize;\n\treturn copy_to_user(statbuf,&tmp,sizeof(tmp)) ? -EFAULT : 0;\n}\n\nSYSCALL_DEFINE2(newstat, const char __user *, filename,\n\t\tstruct stat __user *, statbuf)\n{\n\tstruct kstat stat;\n\tint error;\n\n\terror = vfs_stat(filename, &stat);\n\tif (unlikely(error))\n\t\treturn error;\n\n\treturn cp_new_stat(&stat, statbuf);\n}\n\nSYSCALL_DEFINE2(newlstat, const char __user *, filename,\n\t\tstruct stat __user *, statbuf)\n{\n\tstruct kstat stat;\n\tint error;\n\n\terror = vfs_lstat(filename, &stat);\n\tif (unlikely(error))\n\t\treturn error;\n\n\treturn cp_new_stat(&stat, statbuf);\n}\n\n#if !defined(__ARCH_WANT_STAT64) || defined(__ARCH_WANT_SYS_NEWFSTATAT)\nSYSCALL_DEFINE4(newfstatat, int, dfd, const char __user *, filename,\n\t\tstruct stat __user *, statbuf, int, flag)\n{\n\tstruct kstat stat;\n\tint error;\n\n\terror = vfs_fstatat(dfd, filename, &stat, flag);\n\tif (unlikely(error))\n\t\treturn error;\n\n\treturn cp_new_stat(&stat, statbuf);\n}\n#endif\n\nSYSCALL_DEFINE2(newfstat, unsigned int, fd, struct stat __user *, statbuf)\n{\n\tstruct kstat stat;\n\tint error;\n\n\terror = vfs_fstat(fd, &stat);\n\tif (unlikely(error))\n\t\treturn error;\n\n\treturn cp_new_stat(&stat, statbuf);\n}\n#endif\n\nstatic int do_readlinkat(int dfd, const char __user *pathname,\n\t\t\t char __user *buf, int bufsiz)\n{\n\tstruct path path;\n\tint error;\n\tunsigned int lookup_flags = 0;\n\n\tif (bufsiz <= 0)\n\t\treturn -EINVAL;\n\n\tCLASS(filename_flags, name)(pathname, LOOKUP_EMPTY);\nretry:\n\terror = filename_lookup(dfd, name, lookup_flags, &path, NULL);\n\tif (unlikely(error))\n\t\treturn error;\n\n\t/*\n\t * AFS mountpoints allow readlink(2) but are not symlinks\n\t */\n\tif (d_is_symlink(path.dentry) ||\n\t    d_backing_inode(path.dentry)->i_op->readlink) {\n\t\terror = security_inode_readlink(path.dentry);\n\t\tif (!error) {\n\t\t\ttouch_atime(&path);\n\t\t\terror = vfs_readlink(path.dentry, buf, bufsiz);\n\t\t}\n\t} else {\n\t\terror = (name->name[0] == '\\0') ? -ENOENT : -EINVAL;\n\t}\n\tpath_put(&path);\n\tif (retry_estale(error, lookup_flags)) {\n\t\tlookup_flags |= LOOKUP_REVAL;\n\t\tgoto retry;\n\t}\n\treturn error;\n}\n\nSYSCALL_DEFINE4(readlinkat, int, dfd, const char __user *, pathname,\n\t\tchar __user *, buf, int, bufsiz)\n{\n\treturn do_readlinkat(dfd, pathname, buf, bufsiz);\n}\n\nSYSCALL_DEFINE3(readlink, const char __user *, path, char __user *, buf,\n\t\tint, bufsiz)\n{\n\treturn do_readlinkat(AT_FDCWD, path, buf, bufsiz);\n}\n\n\n/* ---------- LFS-64 ----------- */\n#if defined(__ARCH_WANT_STAT64) || defined(__ARCH_WANT_COMPAT_STAT64)\n\n#ifndef INIT_STRUCT_STAT64_PADDING\n#  define INIT_STRUCT_STAT64_PADDING(st) memset(&st, 0, sizeof(st))\n#endif\n\nstatic long cp_new_stat64(struct kstat *stat, struct stat64 __user *statbuf)\n{\n\tstruct stat64 tmp;\n\n\tINIT_STRUCT_STAT64_PADDING(tmp);\n#ifdef CONFIG_MIPS\n\t/* mips has weird padding, so we don't get 64 bits there */\n\ttmp.st_dev = new_encode_dev(stat->dev);\n\ttmp.st_rdev = new_encode_dev(stat->rdev);\n#else\n\ttmp.st_dev = huge_encode_dev(stat->dev);\n\ttmp.st_rdev = huge_encode_dev(stat->rdev);\n#endif\n\ttmp.st_ino = stat->ino;\n\tif (sizeof(tmp.st_ino) < sizeof(stat->ino) && tmp.st_ino != stat->ino)\n\t\treturn -EOVERFLOW;\n#ifdef STAT64_HAS_BROKEN_ST_INO\n\ttmp.__st_ino = stat->ino;\n#endif\n\ttmp.st_mode = stat->mode;\n\ttmp.st_nlink = stat->nlink;\n\ttmp.st_uid = from_kuid_munged(current_user_ns(), stat->uid);\n\ttmp.st_gid = from_kgid_munged(current_user_ns(), stat->gid);\n\ttmp.st_atime = stat->atime.tv_sec;\n\ttmp.st_atime_nsec = stat->atime.tv_nsec;\n\ttmp.st_mtime = stat->mtime.tv_sec;\n\ttmp.st_mtime_nsec = stat->mtime.tv_nsec;\n\ttmp.st_ctime = stat->ctime.tv_sec;\n\ttmp.st_ctime_nsec = stat->ctime.tv_nsec;\n\ttmp.st_size = stat->size;\n\ttmp.st_blocks = stat->blocks;\n\ttmp.st_blksize = stat->blksize;\n\treturn copy_to_user(statbuf,&tmp,sizeof(tmp)) ? -EFAULT : 0;\n}\n\nSYSCALL_DEF